module top #(
    parameter IDX = 1,
    parameter BIT = 2
) (
    input logic d
);
struct packed {
    logic [7:0] data;
    logic valid;
} cfgs [0:1];
always_comb begin
    {cfgs[IDX].data[BIT], cfgs[IDX].valid} = {cfgs[0].data[0], d};
end
assign cfgs[0].valid = {cfgs[IDX].data[BIT], d};
endmodule

module top #(
    parameter HI = 7,
    parameter LO = 0,
    parameter SEL = 1
) (
    input logic [7:0] a,
    input logic [7:0] d,
    output logic [15:0] y
);
logic [15:0] tmp;
always_comb begin
    tmp = SEL ? (a[HI:LO] + d) : (d << 1);
end
assign y = (a[HI:LO] + d) * 2;
endmodule

